8954   for (VPRecipeBase &R : Header->phis()) {
8955     auto *PhiR = dyn_cast<VPReductionPHIRecipe>(&R);
8956     if (!PhiR || !PhiR->isInLoop() || (MinVF.isScalar() && !PhiR->isOrdered()))
