9022             Blend->replaceAllUsesWith(Blend->getIncomingValue(1));
9023           else {
9024             assert(Blend->getIncomingValue(1) == PhiR &&
9025                    "PhiR must be an operand of the blend");
9026             Blend->replaceAllUsesWith(Blend->getIncomingValue(0));
9027           }
9028           continue;
9029         }
9030 
9031         if (RecurrenceDescriptor::isMinMaxRecurrenceKind(Kind)) {
9032           if (isa<VPWidenRecipe>(CurrentLink)) {
9033             assert(isa<CmpInst>(CurrentLinkI) &&
9034                    "need to have the compare of the select");
9035             continue;
9036           }
9037           assert(isa<VPWidenSelectRecipe>(CurrentLink) &&
9038                  "must be a select recipe");
9039           IndexOfFirstOperand = 1;
9040         } else {
9041           assert((MinVF.isScalar() || isa<VPWidenRecipe>(CurrentLink)) &&
9042                  "Expected to replace a VPWidenSC");
9043           IndexOfFirstOperand = 0;
9044         }
9045         // Note that for non-commutable operands (cmp-selects), the semantics of
9046         // the cmp-select are captured in the recurrence kind.
9047         unsigned VecOpId =
9048             CurrentLink->getOperand(IndexOfFirstOperand) == PreviousLink
9049                 ? IndexOfFirstOperand + 1
9050                 : IndexOfFirstOperand;
9051         VecOp = CurrentLink->getOperand(VecOpId);
9052         assert(VecOp != PreviousLink &&
9053                CurrentLink->getOperand(CurrentLink->getNumOperands() - 1 -
9054                                        (VecOpId - IndexOfFirstOperand)) ==
9055                    PreviousLink &&
9056                "PreviousLink must be the operand other than VecOp");
